('c1900000-0000-0000-0000-000000000087', 'b1900000-0000-0000-0000-000000000007', 7, 'true_false', '[Write TRUE / FALSE / NOT GIVEN] It is thought that the Kelo shelters were occupied continuously until about 1,000 years ago.', 'FALSE', 1),
-- PASSAGE 1: Q8-13 fill_blank
('c1900000-0000-0000-0000-000000000088', 'b1900000-0000-0000-0000-000000000007', 8, 'fill_blank', '[Complete the notes. Choose ONE WORD ONLY from the passage.] Excavations of rock shelters inside ___ (8) near the village of Kelo revealed artefacts.', 'caves', 1),
('c1900000-0000-0000-0000-000000000089', 'b1900000-0000-0000-0000-000000000007', 9, 'fill_blank', '[Complete the notes. Choose ONE WORD ONLY from the passage.] Axes made out of ___ (9), dating from around 11,700 years ago.', 'stone', 1),
